package com.hospital.management.model;
/** Safe patient create/edit input; passwords are excluded from string output. */
public class PatientForm{private Long patientId;private String patientNumber,firstName,lastName,dateOfBirth,gender,bloodGroup,phone,email,address,emergencyContactName,emergencyContactPhone,status,username,password,confirmPassword;private boolean createLoginAccount;
 public Long getPatientId(){return patientId;}public void setPatientId(Long v){patientId=v;}public String getPatientNumber(){return patientNumber;}public void setPatientNumber(String v){patientNumber=v;}public String getFirstName(){return firstName;}public void setFirstName(String v){firstName=v;}public String getLastName(){return lastName;}public void setLastName(String v){lastName=v;}public String getDateOfBirth(){return dateOfBirth;}public void setDateOfBirth(String v){dateOfBirth=v;}public String getGender(){return gender;}public void setGender(String v){gender=v;}public String getBloodGroup(){return bloodGroup;}public void setBloodGroup(String v){bloodGroup=v;}public String getPhone(){return phone;}public void setPhone(String v){phone=v;}public String getEmail(){return email;}public void setEmail(String v){email=v;}public String getAddress(){return address;}public void setAddress(String v){address=v;}public String getEmergencyContactName(){return emergencyContactName;}public void setEmergencyContactName(String v){emergencyContactName=v;}public String getEmergencyContactPhone(){return emergencyContactPhone;}public void setEmergencyContactPhone(String v){emergencyContactPhone=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public boolean isCreateLoginAccount(){return createLoginAccount;}public void setCreateLoginAccount(boolean v){createLoginAccount=v;}public String getUsername(){return username;}public void setUsername(String v){username=v;}public String getPassword(){return password;}public void setPassword(String v){password=v;}public String getConfirmPassword(){return confirmPassword;}public void setConfirmPassword(String v){confirmPassword=v;}public String toString(){return"PatientForm{id="+patientId+", number='"+patientNumber+"'}";}}
